import math

def calculator():
    print("Welcome to the Calculator!")
    print("Please select an operation:")
    print("1. Addition")
    print("2. Subtraction")
    print("3. Multiplication")
    print("4. Division")
    print("5. Exponent")
    print("6. Square Root")
    print("7. Logarithm")
    print("8. Factorial")
    print("9. Sine")
    print("10. Cosine")
    print("11. Tangent")

    choice = input("Enter your choice (1-11): ")

    num1 = float(input("Enter the first number: "))
    num2 = float(input("Enter the second number: "))

    if choice == '1':
        result = num1 + num2
        print("Result:", result)
    elif choice == '2':
        result = num1 - num2
        print("Result:", result)
    elif choice == '3':
        result = num1 * num2
        print("Result:", result)
    elif choice == '4':
        if num2 == 0:
            print("Error: Division by zero")
        else:
            result = num1 / num2
            print("Result:", result)
    elif choice == '5':
        result = num1 ** num2
        print("Result:", result)
    elif choice == '6':
        if num1 < 0:
            print("Error: Cannot find square root of a negative number")
        else:
            result = math.sqrt(num1)
            print("Result:", result)
    elif choice == '7':
        if num1 <= 0 or num2 <= 0:
            print("Error: Logarithm requires positive numbers")
        else:
            result = math.log(num1, num2)
            print("Result:", result)
    elif choice == '8':
        if num1 < 0 or num1 % 1 != 0:
            print("Error: Factorial requires a non-negative integer")
        else:
            result = math.factorial(int(num1))
            print("Result:", result)
    elif choice == '9':
        result = math.sin(math.radians(num1))
        print("Result:", result)
    elif choice == '10':
        result = math.cos(math.radians(num1))
        print("Result:", result)
    elif choice == '11':
        result = math.tan(math.radians(num1))
        print("Result:", result)
    else:
        print("Invalid choice. Please try again.")

calculator()

